/**
 * Format Response for Open WebUI
 * 
 * Structures the final response (with inline images already embedded)
 * in OpenAI-compatible format that Open WebUI expects.
 */

const items = this.getInputData();
const response = items[0].json.generatedResponse || items[0].json.text;
const sessionId = items[0].json.sessionId;
const searchPerformed = items[0].json.searchPerformed !== false;
const contextMetadata = items[0].json.contextMetadata;
const imageEmbeddingMetadata = items[0].json.imageEmbeddingMetadata || {};

// Build sources array for transparency
let sources = [];
if (contextMetadata && contextMetadata.sources) {
  sources = contextMetadata.sources;
}

// OpenAI-compatible response format
const openAIResponse = {
  id: `chatcmpl-${Date.now()}`,
  object: 'chat.completion',
  created: Math.floor(Date.now() / 1000),
  model: 'local-rag-llama3.1',
  output: response,
  usage: {
    prompt_tokens: 0,
    completion_tokens: 0,
    total_tokens: 0
  },
  // Custom metadata for Open WebUI
  metadata: {
    session_id: sessionId,
    search_performed: searchPerformed,
    sources_used: sources,
    images_embedded: imageEmbeddingMetadata.imagesEmbedded || 0,
    timestamp: new Date().toISOString()
  }
};

return [{
  json: openAIResponse
}];

/**
 * Fetch Images from Postgres
 * 
 * Retrieves image data for all imageIds found in the reranked chunks.
 * Converts BYTEA image data to base64 for embedding in markdown.
 */

const { Client } = require('pg');

const items = this.getInputData();
const imageIds = items[0].json.imageIds || [];

// If no images needed, pass through
if (imageIds.length === 0) {
  return [{
    json: {
      ...items[0].json,
      imageData: {}
    }
  }];
}

const connectionString = `postgresql://n8n:n8n_password@postgres:5432/n8n_rag`;

const client = new Client({
  connectionString: connectionString,
  ssl: false,
});

try {
  await client.connect();

  // Query all needed images in a single round-trip
  const placeholders = imageIds.map((_, i) => `$${i + 1}`).join(', ');
  const query = `
    SELECT id, image_data, mimetype, width, height
    FROM document_images
    WHERE id IN (${placeholders})
  `;

  const result = await client.query(query, imageIds);

  // Build a map: imageId -> base64 data
  const imageData = {};
  for (const row of result.rows) {
    const base64 = Buffer.isBuffer(row.image_data) 
      ? row.image_data.toString('base64')
      : Buffer.from(row.image_data).toString('base64');

    imageData[row.id] = {
      base64: base64,
      mimetype: row.mimetype || 'image/png',
      width: row.width,
      height: row.height
    };
  }

  await client.end();

  return [{
    json: {
      ...items[0].json,
      imageData: imageData,
      imagesFetched: Object.keys(imageData).length
    }
  }];

} catch (error) {
  try { await client.end(); } catch (e) {}

  // On error, continue without images rather than failing the whole workflow
  return [{
    json: {
      ...items[0].json,
      imageData: {},
      imagesFetched: 0,
      imageFetchError: error.message
    }
  }];
}

/**
 * Replace Image Markers with Inline Base64 Images
 * 
 * Scans the LLM response for [IMAGE:uuid] markers and replaces them
 * with markdown-embedded base64 images. This ensures images appear
 * inline at contextually relevant positions in the response.
 */

const items = this.getInputData();
const generatedResponse = items[0].json.generatedResponse || '';
const imageData = items[0].json.imageData || {};
const imageMap = items[0].json.imageMap || {};

let finalResponse = generatedResponse;
let imagesEmbedded = 0;
let imagesNotFound = 0;

// Find all [IMAGE:uuid] markers in the response
const imageMarkerRegex = /\[IMAGE:([a-f0-9-]{36})\]/gi;

finalResponse = generatedResponse.replace(imageMarkerRegex, (match, imageId) => {
  const imgData = imageData[imageId];
  const imgMeta = imageMap[imageId];

  if (!imgData) {
    // Image not found in DB — remove the marker cleanly
    imagesNotFound++;
    return '';
  }

  imagesEmbedded++;

  // Build alt text from metadata
  const altText = imgMeta 
    ? `Bild von ${imgMeta.fileName}${imgMeta.page ? ', Page ' + imgMeta.page : ''}`
    : `Dokument-Bild`;

  // Create markdown image with base64 data URI
  // Open WebUI supports inline base64 images in markdown
  const markdownImage = `\n\n![${altText}](data:${imgData.mimetype};base64,${imgData.base64})\n\n`;

  return markdownImage;
});

// Clean up any double blank lines that might result from replacements
finalResponse = finalResponse.replace(/\n{4,}/g, '\n\n\n');

return [{
  json: {
    ...items[0].json,
    generatedResponse: finalResponse,
    imageEmbeddingMetadata: {
      imagesEmbedded: imagesEmbedded,
      imagesNotFound: imagesNotFound,
      totalMarkersFound: imagesEmbedded + imagesNotFound
    }
  }
}];

