/**
 * Extract & Chunk — Docling Hierarchical Chunking API
 *
 * 1. Sends the binary file to the Docling hierarchical chunking API endpoint.
 * 2. Processes the returned chunks to fit the original output format.
 * 3. Extracts pictures with captions/children text, stores images in PostgreSQL,
 *    and creates chunks with image references.
 * 4. Outputs one n8n item per chunk, each with full citation metadata.
 *
 * For plain text / markdown files, reads directly from binary data.
 */

const CHUNK_SIZE = 512;
const DOCLING_URL = 'http://host.docker.internal:5008/v1/chunk/hierarchical/file';

// ── helpers ──────────────────────────────────────────────────

/**
 * Resolve a JSON pointer reference like "#/texts/3" against the DoclingDocument.
 */
function resolveRef(doc, cref) {
  if (!cref) return null;
  const parts = cref.replace(/^#\//, '').split('/');
  let obj = doc;
  for (const p of parts) {
    if (obj == null) return null;
    const idx = Number(p);
    obj = Number.isNaN(idx) ? obj[p] : obj[idx];
  }
  return obj;
}

/**
 * Extract caption / child text from a PictureItem.
 * Looks at captions, children, and meta.description.
 */
function extractPictureText(doc, pictureItem) {
  const textParts = [];

  // 1. Captions (list of RefItems pointing to text items)
  if (Array.isArray(pictureItem.captions)) {
    for (const capRef of pictureItem.captions) {
      const ref = capRef['$ref'] || capRef.cref;
      if (!ref) continue;
      const resolved = resolveRef(doc, ref);
      if (resolved && resolved.text) {
        textParts.push(resolved.text);
      }
    }
  }

  // 2. Children (list of RefItems that may point to text items)
  if (Array.isArray(pictureItem.children)) {
    for (const childRef of pictureItem.children) {
      const ref = childRef['$ref'] || childRef.cref;
      if (!ref) continue;
      const resolved = resolveRef(doc, ref);
      if (resolved && resolved.text && !textParts.includes(resolved.text)) {
        textParts.push(resolved.text);
      }
    }
  }

  // 3. Meta description
  if (pictureItem.meta && pictureItem.meta.description && pictureItem.meta.description.text) {
    const descText = pictureItem.meta.description.text;
    if (!textParts.includes(descText)) {
      textParts.push(descText);
    }
  }

  return textParts.join('\n\n').trim();
}

/**
 * Extract the base64 image data from a PictureItem's image field or embedded URI.
 * Returns { base64: string, mimetype: string } or null.
 */
function extractImageData(pictureItem) {
  if (!pictureItem.image) return null;

  const uri = pictureItem.image.uri;
  if (!uri) return null;

  // Handle data URIs: "data:image/png;base64,..."
  if (typeof uri === 'string' && uri.startsWith('data:')) {
    const match = uri.match(/^data:([^;]+);base64,(.+)$/);
    if (match) {
      return {
        mimetype: match[1],
        base64: match[2],
      };
    }
  }

  return null;
}

/**
 * Store an image as BYTEA in PostgreSQL and return the generated image ID.
 * Expects a table: document_images(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
 *   file_hash TEXT, picture_index INT, image_data BYTEA, mimetype TEXT,
 *   width INT, height INT, created_at TIMESTAMPTZ DEFAULT NOW())
 */
async function storeImageInPostgres(context, imageBase64, mimetype, fileHash, pictureIndex, width, height) {
  // Use the PostgreSQL credential configured in n8n
  const connectionString = `postgresql://n8n:n8n_password@postgres:5432/n8n_rag`;


  const { Client } = require('pg');
  const client = new Client({
    connectionString: connectionString,
    ssl: false,
  });

  await client.connect();

  try {
    // Ensure the table exists
    await client.query(`
      CREATE TABLE IF NOT EXISTS document_images (
        id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
        file_hash TEXT NOT NULL,
        picture_index INT NOT NULL,
        image_data BYTEA NOT NULL,
        mimetype TEXT NOT NULL,
        width INT,
        height INT,
        created_at TIMESTAMPTZ DEFAULT NOW()
      )
    `);

    // Check if this image already exists (idempotent)
    const existing = await client.query(
      'SELECT id FROM document_images WHERE file_hash = $1 AND picture_index = $2 LIMIT 1',
      [fileHash, pictureIndex]
    );

    if (existing.rows.length > 0) {
      return existing.rows[0].id;
    }

    // Decode base64 to binary buffer
    const imageBuffer = Buffer.from(imageBase64, 'base64');

    const insertResult = await client.query(
      `INSERT INTO document_images (file_hash, picture_index, image_data, mimetype, width, height)
       VALUES ($1, $2, $3, $4, $5, $6)
       RETURNING id`,
      [fileHash, pictureIndex, imageBuffer, mimetype, width || null, height || null]
    );

    return insertResult.rows[0].id;
  } finally {
    await client.end();
  }
}

// ── main ─────────────────────────────────────────────────────
const results = [];

for (let idx = 0; idx < items.length; idx++) {
  const item = items[idx];
  const filePath  = item.json.filePath;
  const fileHash  = item.json.fileHash;
  const fileName  = item.json.fileName;
  const extension = item.json.extension;
  const mimeType  = item.json.mimeType;
  const fileSize  = item.json.fileSize;
  const processingMode = item.json.processingMode || 'new';
  const fileId    = item.json.fileId;

  try {
    const binaryPropertyName = 'data';
    const isPlainText = ['txt', 'md', 'rtf'].includes(extension);

    let chunks = [];
    let doclingDocument = null; // Will hold the full DoclingDocument for image extraction

    if (isPlainText) {
      // ── plain text: read directly from binary ──
      const buf = await this.helpers.getBinaryDataBuffer(idx, binaryPropertyName);
      const fullText = buf.toString('utf-8');

      // Create a single chunk for plain text
      chunks = [{
        text: fullText,
        page_numbers: [1],
        headings: [],
        chunk_index: 0
      }];
    } else {
      // ── structured docs: call Docling hierarchical chunking API ──
      const buf = await this.helpers.getBinaryDataBuffer(idx, binaryPropertyName);

      const FormData = require('form-data');
      const form = new FormData();
      form.append('files', buf, {
        filename: fileName,
        contentType: mimeType
      });

      // Chunking parameters
      form.append('chunking_max_tokens', CHUNK_SIZE.toString());
      form.append('chunking_tokenizer', 'sentence-transformers/all-MiniLM-L6-v2');
      form.append('chunking_merge_peers', 'true');
      form.append('chunking_use_markdown_tables', 'false');
      form.append('chunking_include_raw_text', 'false');

      // Conversion parameters
      form.append('convert_ocr_engine', 'rapidocr');
      form.append('include_converted_doc', 'true');

      form.append('convert_include_images', 'true');
      form.append('convert_image_export_mode', 'embedded');

      form.append('convert_do_table_structure', 'true');

      const response = await this.helpers.httpRequest({
        method: 'POST',
        url: DOCLING_URL,
        body: form,
        headers: form.getHeaders(),
        returnFullResponse: true,
        timeout: 120000
      });

      const body = typeof response === 'string'
        ? JSON.parse(response)
        : (response.body
            ? (typeof response.body === 'string' ? JSON.parse(response.body) : response.body)
            : response);

      chunks = body.chunks || [];

      // Extract the DoclingDocument from the response
      // ChunkDocumentResponse has `documents: list[ExportResult]`
      // Each ExportResult has `content: ExportDocumentResponse` with `json_content: DoclingDocument`
      if (Array.isArray(body.documents) && body.documents.length > 0) {
        const exportResult = body.documents[0];
        if (exportResult.content && exportResult.content.json_content) {
          doclingDocument = exportResult.content.json_content;
        }
      }
    }

    // ── process text chunks and emit items ──
    for (let chunkIdx = 0; chunkIdx < chunks.length; chunkIdx++) {
      const chunk = chunks[chunkIdx];
      const chunkText = chunk.text || '';

      if (!chunkText.trim()) continue;

      // Extract page information from the page_numbers array
      const pageNumbers = chunk.page_numbers || [1];
      const pageNumber = pageNumbers.length > 0 ? Math.min(...pageNumbers) : 1;

      const contentType = isPlainText ? extension : (extension === 'pdf' ? 'pdf' : 'office');

      let citationString;
      if (contentType === 'pdf' || contentType === 'office') {
        citationString = `[Source: ${fileName}, Page: ${pageNumber}]`;
      } else {
        citationString = `[Source: ${fileName}]`;
      }

      results.push({
        json: {
          text: chunkText,
          metadata: {
            source: filePath,
            fileName: fileName,
            page: pageNumber,
            totalPages: 0,
            chunk_index: chunk.chunk_index !== undefined ? chunk.chunk_index : chunkIdx,
            chunk_in_page: 0,
            contentType: contentType,
            fileHash: fileHash,
            fileSize: fileSize,
            mimeType: mimeType,
            citationString: citationString,
            processingMode: processingMode,
            fileId: fileId || null,
            headings: chunk.headings || [],
            page_numbers: pageNumbers,
            isImage: false,
          }
        }
      });
    }

    // ── process pictures from DoclingDocument ──
    if (doclingDocument && Array.isArray(doclingDocument.pictures)) {
      for (let picIdx = 0; picIdx < doclingDocument.pictures.length; picIdx++) {
        const picture = doclingDocument.pictures[picIdx];

        // Extract associated text (captions + children text)
        const pictureText = extractPictureText(doclingDocument, picture);

        // Skip pictures without any associated text
        if (!pictureText) continue;

        // Extract image binary data
        const imageData = extractImageData(picture);


        // Skip pictures without embedded image data
        if (!imageData) continue;

        // Determine page number from provenance
        let picPageNumber = 1;
        if (Array.isArray(picture.prov) && picture.prov.length > 0) {
          picPageNumber = picture.prov[0].page_no || 1;
        }

        // Store the image in PostgreSQL
        let imageId = null;
        try {
          const width = picture.image && picture.image.size ? picture.image.size.width : null;
          const height = picture.image && picture.image.size ? picture.image.size.height : null;

          imageId = await storeImageInPostgres(
            this,
            imageData.base64,
            imageData.mimetype,
            fileHash,
            picIdx,
            width,
            height
          );
        } catch (dbError) {
          console.warn(`Failed to store image ${picIdx} in PostgreSQL: ${dbError.message}`);
          // Still create the chunk but without the image reference
        }

        const contentType = extension === 'pdf' ? 'pdf' : 'office';
        const citationString = `[Source: ${fileName}, Page: ${picPageNumber}, Image: ${picIdx}]`;

        // Build the text for embedding: prefix with "[Image]" so downstream
        // consumers know this chunk describes a picture.
        const embeddingText = `[Image] ${pictureText}`;

        results.push({
          json: {
            text: embeddingText,
            metadata: {
              source: filePath,
              fileName: fileName,
              page: picPageNumber,
              totalPages: 0,
              chunk_index: chunks.length + picIdx, // offset after text chunks
              chunk_in_page: 0,
              contentType: contentType,
              fileHash: fileHash,
              fileSize: fileSize,
              mimeType: mimeType,
              citationString: citationString,
              processingMode: processingMode,
              fileId: fileId || null,
              headings: [],
              page_numbers: [picPageNumber],
              isImage: true,
              imageId: imageId, // UUID reference to document_images table
              imageMimetype: imageData.mimetype,
              pictureIndex: picIdx,
              pictureLabel: picture.label || 'picture',
            }
          }
        });
      }
    }

    // If no chunks produced (empty file), emit a marker so DB still updates
    if (results.length === 0 || (chunks.length === 0 && (!doclingDocument || !doclingDocument.pictures || doclingDocument.pictures.length === 0))) {
      results.push({
        json: {
          text: '',
          metadata: {
            source: filePath,
            fileName: fileName,
            page: 0,
            totalPages: 0,
            chunk_index: 0,
            contentType: extension,
            fileHash: fileHash,
            fileSize: fileSize,
            mimeType: mimeType,
            citationString: `[Source: ${fileName}]`,
            processingMode: processingMode,
            fileId: fileId || null,
            empty: true
          }
        }
      });
    }
  } catch (error) {
    // On error, emit an error-marker so the pipeline continues
    results.push({
      json: {
        text: '',
        metadata: {
          source: filePath,
          fileName: fileName,
          page: 0,
          totalPages: 0,
          chunk_index: 0,
          contentType: extension,
          fileHash: fileHash,
          fileSize: fileSize,
          mimeType: mimeType,
          citationString: `[Source: ${fileName}]`,
          processingMode: processingMode,
          fileId: fileId || null,
          error: error.message
        }
      }
    });
  }
}

return results;

