/**
 * Context Assembly with Image Markers and Table Results
 *
 * Formats retrieved documents with citation metadata,
 * tracks image markers, and includes table query results.
 */

const items = this.getInputData();
const userQuery = items[0].json.userQuery;
const tableResults = items[0].json.tableResults;

// Build citation-formatted context and track images
let contextBlocks = [];

// ── TABLE RESULTS ──
let tableContext = '';
let tableCitations = [];
if (tableResults && tableResults.status === 'ok' && tableResults.rows) {
  tableCitations = tableResults.citations || [];
  const cols = tableResults.columns || [];
  const rows = tableResults.rows || [];
  const sql = tableResults.sql || '';
  const explanation = tableResults.explanation || '';

  // Format as markdown table
  let mdTable = '';
  if (cols.length > 0) {
    mdTable += '| ' + cols.join(' | ') + ' |\n';
    mdTable += '| ' + cols.map(() => '---').join(' | ') + ' |\n';
    for (const row of rows.slice(0, 30)) {
      mdTable += '| ' + cols.map(c => String(row[c] ?? '')).join(' | ') + ' |\n';
    }
    if (rows.length > 30) {
      mdTable += `\n... und ${rows.length - 30} weitere Zeilen`;
    }
  }

  tableContext = `\n\n--- TABLE QUERY RESULTS ---\n`
    + `SQL: ${sql}\n`
    + `Explanation: ${explanation}\n`
    + `${tableCitations.join(', ')}\n\n`
    + mdTable;
}

const assembledContext = tableContext;
// Context metadata
const sources = [];

// Add table sources
if (tableCitations.length > 0) {
  for (const tc of tableCitations) {
    sources.push({ source: tc, page: null, score: null });
  }
}

return [{
  json: {
    ...items[0].json,
    assembledContext: assembledContext,
    userQuery: userQuery,
    contextMetadata: {
      sources: sources,
    }
  }
}];

/**
 * Table Search & Query
 *
 * Searches the 'tables' Qdrant
 * collection and executes a SQL query against matching tables.
 * Results are merged into the item for Context Assembly.
 */

const items = this.getInputData();
const result = items[0].json;


let userQuery = null;
try {
  userQuery = $('Parse Response').first().json.userQuery;
} catch (error) {
  userQuery = $('Parse Request QA').first().json.userQuery;
}
const BACKEND_URL = 'http://host.docker.internal:5008';

try {
  // 1. Search the tables collection
  const searchResponse = await this.helpers.httpRequest({
    method: 'POST',
    url: `${BACKEND_URL}/v1/vector-store/search`,
    body: {
      query: userQuery,
      collection_name: 'tables',
      limit: 3,
      rerank: false,
    },
    json: true,
    headers: { 'Content-Type': 'application/json' }
  });

  const tableHits = searchResponse.results || [];
  if (tableHits.length === 0) {
    return [{ json: { ...result, tableResults: null } }];
  }

  // 2. Extract table IDs from search results
  const tableIds = tableHits
    .map(h => h.metadata?.table_id)
    .filter(Boolean);

  if (tableIds.length === 0) {
    return [{ json: { ...result, tableResults: null } }];
  }

  // 3. Execute table query
  const queryResponse = await this.helpers.httpRequest({
    method: 'POST',
    url: `${BACKEND_URL}/v1/tables/query`,
    body: {
      user_query: userQuery,
      table_ids: tableIds
    },
    json: true,
    headers: { 'Content-Type': 'application/json' }
  });

  return [{ json: { ...result, tableResults: queryResponse } }];

} catch (error) {
  // On error, continue without table results
  return [{ json: { ...result, tableResults: null, tableSearchError: error.message } }];
}
